                ['right', { right: '4%', top: '28%', width: '18%', height: '44%' }],
                ['top', { left: '28%', top: '5%', width: '44%', height: '18%' }],
                ['bottom', { left: '28%', bottom: '5%', width: '44%', height: '18%' }],
              ] as const
