  architecture: 'var(--disc-arch-soft)',
  structure: 'var(--disc-struct-soft)',
  mep: 'var(--disc-mep-soft)',
};

const DISC_SOLID: Partial<Record<LensMode, string>> = {
  architecture: 'var(--disc-arch)',
  structure: 'var(--disc-struct)',
  mep: 'var(--disc-mep)',
};

