  await page.goto('http://127.0.0.1:2010/', { waitUntil: 'domcontentloaded' });
  await page.waitForSelector('[data-testid^="canvas-pane-ribbon-"]', { timeout: 15000 });
  const readLayout = async () => page.evaluate(() => {
    const box = (el) => {
      if (!el) return null;
      const r = el.getBoundingClientRect();
      return { x: Math.round(r.x), y: Math.round(r.y), width: Math.round(r.width), height: Math.round(r.height), bottom: Math.round(r.bottom) };
    };
    const pane = document.querySelector('[data-testid^="canvas-pane-tabstrip-"]');
    const header = document.querySelector('[data-testid^="canvas-pane-view-header-"]');
    const secondary = document.querySelector('[data-testid^="canvas-pane-secondary-sidebar-"]');
    const ribbon = document.querySelector('[data-testid^="canvas-pane-ribbon-"]');
    const canvas = document.querySelector('[data-testid="stub-viewport"], [data-testid="stub-plan-canvas"], canvas');
    return { pane: box(pane), header: box(header), secondary: box(secondary), ribbon: box(ribbon), canvas: box(canvas) };
  });
  const open = await readLayout();
  await page.click('[data-testid="ribbon-mode-identity"]');
  await page.waitForFunction(() => !document.querySelector('[data-testid^="canvas-pane-secondary-sidebar-"]'));
  const collapsed = await readLayout();
  console.log(JSON.stringify({ open, collapsed }, null, 2));
  await browser.close();
})();
